    [Fact]
    public void LoadYamlInput()
    {
        string yamlData = """
requestId: exec_abc123
toolCallId: call_abc123
toolName: powershell
success: true
exitCode: 0
durationMs: 250
errorKind: timeout

""";

        var instance = HostToolResult.FromYaml(yamlData);

        Assert.NotNull(instance);
        Assert.Equal("exec_abc123", instance.RequestId);
        Assert.Equal("call_abc123", instance.ToolCallId);
        Assert.Equal("powershell", instance.ToolName);
        Assert.True(instance.Success);
        Assert.Equal(0, instance.ExitCode);
        Assert.Equal(250, instance.DurationMs);
        Assert.Equal("timeout", instance.ErrorKind);
    }

