    [Fact]
    public void RoundtripJson()
    {
        // Test that FromJson -> ToJson -> FromJson produces equivalent data
        string jsonData = """
{
  "requestId": "exec_abc123",
  "toolCallId": "call_abc123",
  "toolName": "powershell",
  "success": true,
  "exitCode": 0,
  "durationMs": 250,
  "errorKind": "timeout"
}
""";

        var original = HostToolResult.FromJson(jsonData);
        Assert.NotNull(original);

        var json = original.ToJson();
        Assert.False(string.IsNullOrEmpty(json));

        var reloaded = HostToolResult.FromJson(json);
        Assert.NotNull(reloaded);
        Assert.Equal("exec_abc123", reloaded.RequestId);
        Assert.Equal("call_abc123", reloaded.ToolCallId);
        Assert.Equal("powershell", reloaded.ToolName);
        Assert.True(reloaded.Success);
        Assert.Equal(0, reloaded.ExitCode);
        Assert.Equal(250, reloaded.DurationMs);
        Assert.Equal("timeout", reloaded.ErrorKind);
    }

